// ===== UTILITAIRES =====
function formatPrice(n) {
    return n.toLocaleString("fr-FR", { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + " €";
}

function showToast(msg) {
    toast.textContent = msg;
    toast.classList.add("show");
    clearTimeout(showToast._t);
    showToast._t = setTimeout(() => toast.classList.remove("show"), 2500);
}

function getFilteredProducts() {
    const { type, value } = currentFilter;
    if (type === "all") return PRODUITS;
    if (type === "featured") return PRODUITS.filter((p) => p.featured);
    if (type === "category") return PRODUITS.filter((p) => p.category === value);
    if (type === "product") return PRODUITS.filter((p) => p.id === value);
    return PRODUITS;
}

function lowestPrice(product) {
    return Math.min(...product.variants.map((v) => v.price));
}

// ===== LOGO FALLBACK =====
document.getElementById("logoImg")?.addEventListener("error", function () {
    this.src = "assets/logo-fallback.svg";
});

// ===== SUGGESTIONS =====
function renderSuggestions() {
    suggestionsList.innerHTML = "";
    SUGGESTIONS.forEach((s) => {
        const btn = document.createElement("button");
        btn.type = "button";
        btn.className = "suggestion-chip" + (activeSuggestion === s.label ? " active" : "");
        btn.dataset.type = s.type;
        if (s.value !== undefined) btn.dataset.value = s.value;
        btn.dataset.label = s.label;

        const product = s.type === "product" ? PRODUITS.find((p) => p.id === s.value) : null;
        btn.innerHTML = product
            ? `<img src="${product.image}" alt="" class="chip-thumb" /><span>${s.emoji} ${s.label}</span>`
            : `<span class="chip-emoji">${s.emoji}</span><span>${s.label}</span>`;

        btn.addEventListener("click", () => onSuggestionClick(s, btn));
        suggestionsList.appendChild(btn);
    });
}

function onSuggestionClick(s, btn) {
    activeSuggestion = s.label;
    suggestionsList.querySelectorAll(".suggestion-chip").forEach((b) => b.classList.remove("active"));
    btn.classList.add("active");

    if (s.type === "product") {
        const product = PRODUITS.find((p) => p.id === s.value);
        if (product) openProductDetail(product);
        currentFilter = { type: "all" };
        catalogTitle.textContent = "Catalogue";
        renderCatalog();
        return;
    }

    currentFilter = { type: s.type, value: s.value };
    catalogTitle.textContent = s.type === "all" ? "Catalogue" : s.label;
    renderCatalog();
}

// ===== CATALOGUE =====
function renderCatalog() {
    const filtered = getFilteredProducts();

    if (filtered.length === 0) {
        grid.innerHTML = `<p class="empty-catalog">Aucun produit dans cette sélection.</p>`;
        return;
    }

    grid.innerHTML = "";
    filtered.forEach((p, i) => {
        const card = document.createElement("button");
        card.type = "button";
        card.className = "product-card";
        card.style.animationDelay = `${i * 0.05}s`;
        card.innerHTML = `
            <div class="card-image">
                <img src="${p.image}" alt="${p.name}" loading="lazy" />
                <span class="card-emoji">${p.emoji || ""}</span>
            </div>
            <div class="card-body">
                <span class="card-brand">${p.brand}</span>
                <h3 class="card-name">${p.name}</h3>
                <span class="card-price">À partir de ${formatPrice(lowestPrice(p))}</span>
            </div>
            <span class="card-tap">Voir le détail →</span>`;
        card.addEventListener("click", () => openProductDetail(p));
        grid.appendChild(card);
    });
}

// ===== FICHE PRODUIT =====
function openProductDetail(product) {
    currentProduct = product;
    selectedVariant = null;
    detailQty = 1;

    const detailImage = document.getElementById("detailImage");
    const detailVideo = document.getElementById("detailVideo");
    const toggleMediaBtn = document.getElementById("toggleMediaBtn");

    // Si le produit a une vidéo, la montrer en premier et la lancer
    if (product.video) {
        detailVideo.src = product.video;
        detailImage.style.display = "none";
        detailVideo.style.display = "block";
        detailVideo.play().catch(() => {
            // Fallback si l'autoplay est bloqué
            console.log("Autoplay bloqué par le navigateur");
        });
        toggleMediaBtn.style.display = "flex";
        toggleMediaBtn.classList.add("video-active");
        toggleMediaBtn.innerHTML = '<i class="fas fa-image"></i>';
        toggleMediaBtn.title = "Afficher l\'image";
    } else {
        // Sinon, afficher l'image
        detailImage.src = product.image || "";
        detailImage.alt = product.name;
        detailImage.style.display = "block";
        detailVideo.src = "";
        detailVideo.style.display = "none";
        toggleMediaBtn.style.display = "none";
    }

    document.getElementById("detailBrand").textContent = `${product.emoji || ""} ${product.brand}`;
    document.getElementById("detailName").textContent = product.name;
    document.getElementById("detailStrain").textContent = product.strain || "";
    document.getElementById("detailQty").textContent = "1";

    const variantsEl = document.getElementById("detailVariants");
    variantsEl.innerHTML = product.variants
        .map(
            (v) => `
        <button type="button" class="variant-pill" data-weight="${v.weight}" data-price="${v.price}">
            <span class="variant-weight">${v.weight}</span>
            <span class="variant-price">${formatPrice(v.price)}</span>
        </button>`
        )
        .join("");

    variantsEl.querySelectorAll(".variant-pill").forEach((pill) => {
        pill.addEventListener("click", () => selectVariant(pill));
    });

    updateDetailButtons();
    productOverlay.hidden = false;
    document.body.style.overflow = "hidden";
}

function selectVariant(pill) {
    document.querySelectorAll(".variant-pill").forEach((p) => p.classList.remove("active"));
    pill.classList.add("active");
    selectedVariant = {
        weight: pill.dataset.weight,
        price: parseFloat(pill.dataset.price)
    };
    updateDetailButtons();
}

function updateDetailButtons() {
    const hint = document.getElementById("detailHint");
    const grammageBtn = document.getElementById("detailGrammageBtn");
    const addBtn = document.getElementById("detailAddCart");

    if (selectedVariant) {
        hint.classList.add("hidden");
        grammageBtn.classList.add("hidden");
        addBtn.disabled = false;
        addBtn.textContent = `Ajouter — ${formatPrice(selectedVariant.price * detailQty)}`;
    } else {
        hint.classList.remove("hidden");
        grammageBtn.classList.remove("hidden");
        addBtn.disabled = true;
        addBtn.textContent = "Ajouter au panier";
    }
}

function closeProductDetail() {
    productOverlay.hidden = true;
    document.body.style.overflow = "";
    currentProduct = null;
}

document.getElementById("closeProduct").addEventListener("click", closeProductDetail);
productOverlay.addEventListener("click", (e) => {
    if (e.target === productOverlay) closeProductDetail();
});

document.getElementById("detailQtyMinus").addEventListener("click", () => {
    if (detailQty > 1) {
        detailQty--;
        document.getElementById("detailQty").textContent = detailQty;
        updateDetailButtons();
    }
});

document.getElementById("detailQtyPlus").addEventListener("click", () => {
    detailQty++;
    document.getElementById("detailQty").textContent = detailQty;
    updateDetailButtons();
});

document.getElementById("detailGrammageBtn").addEventListener("click", () => {
    showToast("Choisissez un grammage ci-dessus");
});

document.getElementById("detailAddCart").addEventListener("click", () => {
    if (!currentProduct || !selectedVariant) return;
    ajouterAuPanier(currentProduct, selectedVariant.weight, selectedVariant.price, detailQty);
    closeProductDetail();
});

document.getElementById("detailTelegram").addEventListener("click", () => {
    window.open(TELEGRAM_CHANNEL, "_blank");
});

// Basculer entre image et vidéo
document.getElementById("toggleMediaBtn").addEventListener("click", () => {
    const detailImage = document.getElementById("detailImage");
    const detailVideo = document.getElementById("detailVideo");
    const toggleBtn = document.getElementById("toggleMediaBtn");

    if (detailImage.style.display !== "none") {
        // Afficher la vidéo
        detailImage.style.display = "none";
        detailVideo.style.display = "block";
        toggleBtn.classList.add("video-active");
        toggleBtn.innerHTML = '<i class="fas fa-image"></i>';
        toggleBtn.title = "Afficher l\'image";
    } else {
        // Afficher l'image
        detailImage.style.display = "block";
        detailVideo.style.display = "none";
        toggleBtn.classList.remove("video-active");
        toggleBtn.innerHTML = '<i class="fas fa-video"></i>';
        toggleBtn.title = "Afficher la vidéo";
    }
});

// ===== PANIER =====
function ajouterAuPanier(product, weight, price, qty = 1) {
    const existant = panier.find((p) => p.productId === product.id && p.weight === weight);

    if (existant) {
        existant.quantite += qty;
    } else {
        panier.push({
            productId: product.id,
            name: product.name,
            brand: product.brand,
            weight,
            price,
            image: product.image,
            quantite: qty
        });
    }

    updateCartUI();
    saveCart();
    showToast(`${product.name} ajouté au panier`);
    floatingBadge.style.transform = "scale(1.4)";
    setTimeout(() => (floatingBadge.style.transform = ""), 300);
}

function updateCartUI() {
    const totalItems = panier.reduce((s, i) => s + i.quantite, 0);
    const totalPrice = panier.reduce((s, i) => s + i.price * i.quantite, 0);

    headerCartCount.textContent = totalItems;
    floatingBadge.textContent = totalItems;
    cartTotalPrice.textContent = formatPrice(totalPrice);

    if (panier.length === 0) {
        cartItems.innerHTML = `<p class="empty-cart">Votre panier est vide</p>`;
        return;
    }

    cartItems.innerHTML = panier
        .map(
            (item, index) => `
        <div class="cart-item">
            <img src="${item.image}" alt="${item.name}" />
            <div class="cart-item-details">
                <div class="cart-item-name">${item.name}</div>
                <div class="cart-item-variant">${item.weight} · ${item.brand}</div>
                <div class="cart-item-price">${formatPrice(item.price * item.quantite)}</div>
            </div>
            <div class="cart-item-actions">
                <button type="button" data-index="${index}" data-delta="-1">−</button>
                <span>${item.quantite}</span>
                <button type="button" data-index="${index}" data-delta="1">+</button>
                <button type="button" class="cart-remove" data-index="${index}"><i class="fas fa-trash"></i></button>
            </div>
        </div>`
        )
        .join("");

    cartItems.querySelectorAll("[data-delta]").forEach((btn) => {
        btn.addEventListener("click", () => modifierQuantite(+btn.dataset.index, +btn.dataset.delta));
    });
    cartItems.querySelectorAll(".cart-remove").forEach((btn) => {
        btn.addEventListener("click", () => supprimerDuPanier(+btn.dataset.index));
    });
}

function modifierQuantite(index, delta) {
    const item = panier[index];
    if (!item) return;
    const q = item.quantite + delta;
    if (q <= 0) panier.splice(index, 1);
    else item.quantite = q;
    updateCartUI();
    saveCart();
}

function supprimerDuPanier(index) {
    panier.splice(index, 1);
    updateCartUI();
    saveCart();
}

function saveCart() {
    localStorage.setItem("liners_cart", JSON.stringify(panier));
}

function loadCart() {
    try {
        const saved = localStorage.getItem("liners_cart");
        if (saved) panier = JSON.parse(saved);
    } catch {
        panier = [];
    }
}

function openCart() {
    cartSidebar.classList.add("open");
    cartOverlay.classList.add("open");
}

function closeCart() {
    cartSidebar.classList.remove("open");
    cartOverlay.classList.remove("open");
}

document.getElementById("headerCart").addEventListener("click", openCart);
document.getElementById("floatingCart").addEventListener("click", openCart);
document.getElementById("closeCart").addEventListener("click", closeCart);
cartOverlay.addEventListener("click", closeCart);

document.getElementById("checkoutBtn").addEventListener("click", () => {
    window.open(TELEGRAM_CHANNEL, "_blank");
});

document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") {
        if (!productOverlay.hidden) closeProductDetail();
        else closeCart();
    }
});

// ===== NAVIGATION =====
function showPage(pageName) {
    // Masquer toutes les pages
    document.getElementById("catalogPage")?.setAttribute("hidden", "");
    document.getElementById("catalogPage2")?.setAttribute("hidden", "");
    document.getElementById("canalPage")?.setAttribute("hidden", "");
    document.getElementById("infoPage")?.setAttribute("hidden", "");

    // Retirer la classe active de tous les boutons nav
    document.querySelectorAll(".nav-btn").forEach((btn) => btn.classList.remove("nav-active"));

    // Afficher la page sélectionnée
    if (pageName === "catalog") {
        document.getElementById("catalogPage")?.removeAttribute("hidden");
        document.getElementById("catalogPage2")?.removeAttribute("hidden");
        document.getElementById("navCatalog").classList.add("nav-active");
    } else if (pageName === "canal") {
        document.getElementById("canalPage")?.removeAttribute("hidden");
        document.getElementById("navCanal").classList.add("nav-active");
    } else if (pageName === "info") {
        document.getElementById("infoPage")?.removeAttribute("hidden");
        document.getElementById("navInfo").classList.add("nav-active");
    }
}

// Event listeners pour la navigation
document.querySelectorAll(".nav-btn").forEach((btn) => {
    btn.addEventListener("click", () => {
        const page = btn.dataset.page;
        showPage(page);
    });
});

